    await runPluginHook(state.plugins, 'onResponse', ctx, helpers);

    const statusCode = ctx.res.statusCode || 502;
    const headers = sanitizeHeaders(ctx.res.headers || {}, cfg.allowHopByHop);
    if (cfg.strictHeaderValidation) strictValidateHeaders(headers);

    writeResponse(res, statusCode, headers, ctx.res.body);
